}

static void Radix32(UL *source,int N)

{

  UL *temp =(UL*)malloc(N*sizeof(UL));

  radix(0,N,source,temp);

  radix(8,N,temp,source);

  radix(16,N,source,temp);

  radix(24,N,temp,source);

  free(temp);

}

